import React, { useState } from "react";

function CompareModels() {
  const [results, setResults] = useState(null);
  const [error, setError] = useState("");

  const runCompare = async () => {
    setError("");
    setResults(null);

    try {
      const res = await fetch("http://127.0.0.1:5000/compare", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({})
      });

      const data = await res.json();
      console.log("API RESPONSE:", data); // 🔥 IMPORTANT

      if (data.status === "success") {
        setResults(data.results);
      } else {
        setError(data.message || "Error from backend");
      }

    } catch (err) {
      setError("Backend connection failed");
    }
  };

  // 🔥 Convert value safely to percentage
  const formatPercent = (val) => {
    if (val === undefined || val === null) return "0.00%";

    // if already like 85 → keep
    if (val > 1) return val.toFixed(2) + "%";

    // if 0.72 → convert
    return (val * 100).toFixed(2) + "%";
  };

  const getModel = (res, keys) => {
    for (let k of keys) {
      if (res && res[k]) return res[k];
    }
    return null;
  };

  const formatBlock = (title, m) => {
    if (!m) return `${title}\nNo data\n`;

    return `${title}
TPR: ${formatPercent(m.TPR)}
FNR: ${formatPercent(m.FNR)}
FPR: ${formatPercent(m.FPR)}
TNR: ${formatPercent(m.TNR)}
F1 Score: ${formatPercent(m.F1)}
Confusion → TN: ${m.TN ?? 0} | FP: ${m.FP ?? 0} | FN: ${m.FN ?? 0} | TP: ${m.TP ?? 0}
`;
  };

  
  const iso = getModel(results, ["isolation_forest", "IsolationForest"]);

  return (
    <div style={{ padding: "20px" }}>
      <h2>Model Comparison</h2>

      <button onClick={runCompare}>Run Comparison</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {results && (
        <pre style={{ marginTop: "20px", background: "#f4f4f4", padding: "15px" }}>


{formatBlock("Isolation Forest", iso)}
        </pre>
      )}
    </div>
  );
}

export default CompareModels;
